// 1. Get the raw text output from the previous Gemini node
const rawText = $input.item.json.candidates[0].content.parts[0].text || "";

// --- Helper Function: Extract text between two headers (Flexible) ---
function extractSection(text, startHeader, endHeader) {
  if (!text) return null;

  // Escape special regex characters in the header string
  const escapedHeader = startHeader
    .replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
    .replace(/\s+/g, '\\s+');

  // Start Pattern: matches optional numbering, bolding, hashes, etc.
  const startPattern =
    `(?:^|\\n)` +                      // start of string or newline
    `(?:[\\#>\\d\\.\\)\\-\\s]*)?` +    // optional markdown prefixes / numbers
    `(?:\\*\\*|__)?` +                 // optional bold start
    `${escapedHeader}` +               // the header text itself
    `(?:.*?)?` +                       // optional trailing chars
    `(?:\\*\\*|__)?` +                 // optional bold end
    `[:\\s]*`;                         // optional colon / spaces

  const startRegex = new RegExp(startPattern, 'i');
  const startMatch = text.match(startRegex);

  if (!startMatch) return null;

  const startIndex = startMatch.index + startMatch[0].length;

  // Find End Index
  let endIndex = text.length;
  if (endHeader) {
    const endHeaders = Array.isArray(endHeader) ? endHeader : [endHeader];
    const combinedEndPattern = endHeaders.map(h => {
      const esc = h
        .replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
        .replace(/\s+/g, '\\s+');
      return `(?:^|\\n)(?:[\\#>\\d\\.\\)\\-\\s]*)?(?:\\*\\*|__)?${esc}`;
    }).join('|');

    const endRegex = new RegExp(combinedEndPattern, 'i');
    const remainingText = text.substring(startIndex);
    const endMatch = remainingText.match(endRegex);

    if (endMatch) {
      endIndex = startIndex + endMatch.index;
    }
  }

  return text.substring(startIndex, endIndex).trim();
}

// --- Helper Function: Robust JSON Parsing ---
function parseJSONBlock(rawString) {
  if (!rawString) return {};
  try {
    // 1. Find the index of the first '{'
    const firstBrace = rawString.indexOf('{');
    // 2. Find the index of the last '}'
    const lastBrace = rawString.lastIndexOf('}');

    // 3. If valid braces found, extract ONLY that substring
    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
      const jsonCandidate = rawString.substring(firstBrace, lastBrace + 1);
      return JSON.parse(jsonCandidate);
    }

    // Fallback: simple cleanup if braces methodology fails
    let cleanString = rawString
      .replace(/```json/g, '')
      .replace(/```/g, '');
    return JSON.parse(cleanString);
  } catch (e) {
    return {
      error: "Failed to parse JSON",
      raw_text: rawString,
      message: e.message,
    };
  }
}

// --- MAIN EXTRACTION LOGIC ---

// 1) Parse the main JSON object from the full Gemini output
const mainObj = parseJSONBlock(rawText) || {};

// Safely unpack sub-objects
const configObj = mainObj.config || {};
const selectedConfig = configObj.selected_config || {};
const recommendedConfig = configObj.recommended_config || {};
const effectiveConfig = configObj.effective_config || {};

const marketResearch = mainObj.market_research || {};
const personaObj = mainObj.persona || {};
const productObj = mainObj.product_profile || {};
const performanceForecast = mainObj.performance_forecast || {};
const strategy = mainObj.strategy || {};

// 2) Extract the START FRAME IMAGE PROMPT section
// Header in prompt: "### START FRAME IMAGE PROMPT"
const frame0Prompt = extractSection(
  rawText,
  "START FRAME IMAGE PROMPT",
  "SORA PROMPT BLOCK"
);

// 3) Extract the SORA PROMPT BLOCK section
// Header in prompt: "### SORA PROMPT BLOCK"
// This is the final section, so no endHeader
const soraVideoPrompt = extractSection(
  rawText,
  "SORA PROMPT BLOCK",
  null
);

// 4) Optional: derive a simple research_summary string for backward compatibility
const researchSummary =
  marketResearch.summary_of_patterns ||
  marketResearch.inferred_category ||
  "";

// --- RETURN STRUCTURED DATA ---
return {
  json: {
    raw_text: rawText,                 // full Gemini output (debugging / logging)

    // New structured fields from JSON
    config: configObj,
    selected_config: selectedConfig,
    recommended_config: recommendedConfig,
    effective_config: effectiveConfig,
    market_research: marketResearch,
    persona: personaObj,
    product_profile: productObj,
    performance_forecast: performanceForecast,
    strategy: strategy,

    // Backward-compatible / convenience fields
    vid_config: effectiveConfig,                       // effective config for video generation
    research_summary: researchSummary,                 // short summary string if you need it
    strategy_snapshot: strategy,                       // whole strategy object

    // Sora + image-model facing text blocks
    start_frame_image_prompt: frame0Prompt,
    vidgen_prompt: soraVideoPrompt
  }
};

