const newItems = [];

// 1. Get the single input item from the form
const item = $input.item;

// 2. Check if binary data exists
if (item.binary) {
  // 3. Loop through every uploaded file (data, data_1, data_2)
  for (const key of Object.keys(item.binary)) {
    const binaryFile = item.binary[key];

    // 4. Create a separate item for each file
    // We keep the original JSON fields (Product Name, etc) on every item
    newItems.push({
      json: {
        ...item.json,
        originalBinaryKey: key // tracking ID
      },
      binary: {
        data: binaryFile // Standardize the binary key to just 'data' for the upload node
      }
    });
  }
}

return newItems;

// 1. Get the raw Master Prompt string
const sourceJson = $('set_master_prompt').first().json;
const rawPromptString = sourceJson.text || sourceJson.prompt || sourceJson.promptText;

// 2. Define the 'parts' array
const parts = [];

// 3. Add the Text Part
if (rawPromptString) {
  parts.push({
    "text": rawPromptString
  });
} else {
  parts.push({
    "text": "Error: Prompt text not found."
  });
}

// 4. Get the Images from 'Aggregate image URLs and Format'
const imageList = $('aggregate_images_urls_and_format_inputs').first().json.images || [];

// 5. Loop through images and add ONLY the sanitized inline_data
for (const img of imageList) {
  if (img.inline_data) {
    // We explicitly create a new object to STRIP OUT 'public_url' and 'fileName'
    parts.push({
      inline_data: {
        mime_type: img.inline_data.mime_type || "image/jpeg",
        data: img.inline_data.data
      }
    });
  } 
  else if (img.data) {
    parts.push({
      inline_data: {
        "mime_type": img.mimeType || "image/jpeg",
        "data": img.data
      }
    });
  }
}

// 6. Return the FULL API BODY structure
// This constructs the exact JSON object Gemini needs: { "contents": [ ... ] }
return {
  json: {
    contents: [
      {
        parts: parts
      }
    ]
  }
};

const processedImages = [];

// 1. Get the URLs from the current input (Cloudinary output)
const cloudinaryItems = $input.all();

// 2. Get the Base64 data from the earlier 'Split files' node
// We have to reach back because Cloudinary stripped the binary data
const splitItems = $('split_product_images').all();

// 3. Loop through the items and merge them
for (let i = 0; i < cloudinaryItems.length; i++) {
  const cloudItem = cloudinaryItems[i];
  // We grab the corresponding item from the split node using the same index
  const splitItem = splitItems[i]; 

  if (splitItem && splitItem.binary && splitItem.binary.data) {
    // Extract URL (from Cloudinary)
    const publicUrl = cloudItem.json.secure_url;

    // Extract Base64 (from Split node)
    const binaryData = splitItem.binary.data;

    processedImages.push({
      // For Gemini (Base64)
      inline_data: {
        mime_type: binaryData.mimeType,
        data: binaryData.data
      },
      // For Sora/Nano (URL)
      public_url: publicUrl,
      // Metadata
      fileName: binaryData.fileName
    });
  }
}

// 4. Return the combined result
// We grab the original form data from the first split item
const originalData = splitItems.length > 0 ? splitItems[0].json : {};

return {
  json: {
    ...originalData, // Keeps Product Name, Duration, etc.
    images: processedImages
  }
};
